"use client";

import Image from "next/image";
import { useRouter } from "next/navigation";
import { X, Trash2, ShoppingBag } from "lucide-react";
import { useCartStore } from "../store/useCartStore";

export default function CartDrawer() {
  const router = useRouter();
  const { items, isOpen, toggleCart, removeItem, getTotal } = useCartStore();

  if (!isOpen) return null;

  const handleCheckout = () => {
    toggleCart(); // Close drawer
    router.push("/checkout"); // Route to true checkout page
  };

  return (
    <>
      {/* Background Overlay */}
      <div
        className="fixed inset-0 z-[80] bg-black/60 backdrop-blur-sm transition-opacity"
        onClick={toggleCart}
      />

      {/* Drawer Panel */}
      <div className="fixed inset-y-0 right-0 z-[90] flex w-full max-w-md flex-col bg-[#fcfcfc] dark:bg-[#050505] shadow-2xl sm:w-[500px] animate-in slide-in-from-right duration-500 border-l border-gray-200 dark:border-white/10">

        {/* Header */}
        <div className="flex items-center justify-between border-b border-gray-200 p-8 dark:border-white/10">
          <h2 className="font-cinzel text-xl tracking-widest text-gray-900 dark:text-white uppercase flex items-center gap-4">
            Curated Collection
          </h2>
          <button onClick={toggleCart} className="p-2 text-gray-400 hover:text-gray-900 dark:hover:text-white transition-colors">
            <X className="h-5 w-5" strokeWidth={1} />
          </button>
        </div>

        {/* Cart Items */}
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {items.length === 0 ? (
            <div className="flex h-full flex-col items-center justify-center text-center">
              <ShoppingBag className="mb-6 h-12 w-12 text-gray-200 dark:text-gray-800" strokeWidth={1} />
              <p className="font-cinzel text-lg tracking-widest uppercase text-gray-400 mb-2">No Acquisitions</p>
              <p className="text-xs font-light tracking-wide text-gray-500">Your collection awaits.</p>
            </div>
          ) : (
            <div className="flex flex-col gap-8">
              {items.map((item) => (
                <div key={item.id} className="group relative flex items-start gap-6 border-b border-gray-100 dark:border-white/5 pb-8 last:border-0 last:pb-0">
                  <div className="relative h-28 w-20 overflow-hidden bg-gray-50 dark:bg-gray-900 ring-1 ring-gray-200 dark:ring-white/10">
                    <Image src={item.image} alt={item.title} fill className="object-cover" />
                  </div>
                  <div className="flex flex-1 flex-col justify-between min-h-[7rem]">
                    <div className="pr-4">
                      <h3 className="font-cinzel text-sm leading-relaxed tracking-wider text-gray-900 dark:text-white line-clamp-2 uppercase">
                        {item.title}
                      </h3>
                      <p className="text-[10px] font-semibold tracking-widest uppercase text-gray-400 mt-2">
                        Qty: {item.quantity}
                      </p>
                    </div>
                    <div className="flex items-center justify-between mt-4">
                      <p className="font-cinzel text-sm tracking-wider text-gray-900 dark:text-white">
                        ${(item.price * item.quantity).toFixed(2)}
                      </p>
                      <button
                        onClick={() => removeItem(item.id)}
                        className="text-[10px] font-semibold tracking-widest uppercase text-gray-400 hover:text-red-600 transition-colors"
                      >
                        Remove
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer / Checkout */}
        {items.length > 0 && (
          <div className="border-t border-gray-200 p-8 dark:border-white/10">
            <div className="mb-8 flex items-end justify-between">
              <span className="font-cinzel text-xs font-semibold tracking-widest text-gray-500 uppercase">Subtotal</span>
              <span className="font-cinzel text-2xl tracking-wider text-gray-900 dark:text-white">${getTotal().toFixed(2)}</span>
            </div>
            <button
              onClick={handleCheckout}
              className="w-full border border-gray-900 bg-gray-900 py-5 text-xs font-semibold tracking-widest uppercase text-white transition-all hover:bg-transparent hover:text-gray-900 dark:border-white dark:bg-white dark:text-black dark:hover:bg-transparent dark:hover:text-white"
            >
              Finalize Acquisition
            </button>
            <p className="mt-6 text-center text-[9px] font-light tracking-[0.2em] text-gray-400 uppercase">
              Shipping & taxes calculated at checkout.
            </p>
          </div>
        )}
      </div>
    </>
  );
}

"use client";

import Link from "next/link";
import { useRouter, usePathname } from "next/navigation";
import { useTheme } from "next-themes";
import { useEffect, useState } from "react";
import { Search, ShoppingBag, User, Moon, Sun, Menu } from "lucide-react";
import { useCartStore } from "../store/useCartStore";
import MobileMenu from "./MobileMenu";

export default function Navbar() {
  const { theme, setTheme, resolvedTheme } = useTheme();
  const [searchQuery, setSearchQuery] = useState("");
  const router = useRouter();
  const pathname = usePathname();
  const isLandingPage = pathname === "/";
  const [scrolled, setScrolled] = useState(false);

  const [mounted, setMounted] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const { items, toggleCart } = useCartStore();
  const totalItems = items.reduce((sum, item) => sum + item.quantity, 0);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      router.push(`/explore?q=${encodeURIComponent(searchQuery)}`);
    }
  };

  useEffect(() => {
    setMounted(true);
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <>
      <nav className={`fixed top-0 inset-x-0 z-50 transition-all duration-300 ${scrolled ? "bg-[#fcfcfc]/80 backdrop-blur-md border-b border-gray-200 dark:bg-[#050505]/80 dark:border-white/10" : "bg-transparent border-transparent"}`}>
        <div className={`mx-auto flex max-w-7xl items-center justify-between px-4 py-4 sm:px-6 lg:px-8 ${!scrolled && isLandingPage ? "text-gray-900 dark:text-white" : "text-gray-900 dark:text-white"}`}>

          {/* Left: Hamburger (Mobile) + Logo */}
          <div className="flex items-center gap-4">
            {!isLandingPage && (
              <button
                onClick={() => setIsMobileMenuOpen(true)}
                className={`p-2 transition-colors ${!scrolled && isLandingPage ? "hover:text-gray-600 dark:hover:text-gray-300" : "hover:text-black dark:hover:text-white"}`}
              >
                <Menu className="h-5 w-5" strokeWidth={1} />
              </button>
            )}

            <Link href="/" className="flex items-center group">
              <span className={`font-cinzel text-xl sm:text-2xl font-medium tracking-[0.2em] uppercase transition-opacity hover:opacity-70 ${!scrolled && isLandingPage ? "text-gray-900 dark:text-white" : "text-gray-900 dark:text-white"}`}>
                AKI.
              </span>
            </Link>
          </div>

          {/* Center: Search Bar */}
          <div className={`${isLandingPage ? 'hidden' : 'hidden md:flex'} flex-1 items-center justify-center px-8`}>
            <form onSubmit={handleSearch} className="relative w-full max-w-sm group">
              <input
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search collections..."
                className="w-full rounded-none border-b border-gray-300 bg-transparent px-2 py-2 pl-8 text-sm text-gray-900 focus:border-gray-900 focus:outline-none dark:border-gray-700 dark:text-gray-100 dark:focus:border-white transition-colors duration-300 tracking-wide font-light placeholder-gray-400"
              />
              <Search className="absolute left-0 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400 transition-colors" strokeWidth={1} />
            </form>
          </div>

          {/* Right: Icons & Actions */}
          <div className="flex items-center gap-4 sm:gap-6">

            {/* Theme Toggle */}
            {mounted && (
              <button
                onClick={() => setTheme(resolvedTheme === "dark" ? "light" : "dark")}
                className="text-gray-900 hover:text-gray-500 dark:text-white dark:hover:text-gray-400 transition-colors"
                aria-label="Toggle Dark Mode"
              >
                {resolvedTheme === "dark" ? <Sun className="h-4 w-4" strokeWidth={1.5} /> : <Moon className="h-4 w-4" strokeWidth={1.5} />}
              </button>
            )}

            {isLandingPage ? (
              <Link
                href="/auth/signup"
                className="border border-gray-900 bg-transparent px-6 py-2.5 text-[10px] sm:text-xs font-semibold tracking-widest text-gray-900 transition-all duration-300 hover:bg-gray-900 hover:text-white dark:border-white dark:text-white dark:hover:bg-white dark:hover:text-black uppercase"
              >
                Start Shop
              </Link>
            ) : (
              <Link
                href="/account"
                className="text-gray-900 hover:text-gray-500 dark:text-white dark:hover:text-gray-400 transition-colors"
                title="Your Account"
              >
                <User className="h-4 w-4" strokeWidth={1} />
              </Link>
            )}

            {/* Cart Icon */}
            {!isLandingPage && (
              <button
                onClick={toggleCart}
                className="relative text-gray-900 hover:text-gray-500 dark:text-white dark:hover:text-gray-400 transition-colors"
              >
                <ShoppingBag className="h-4 w-4" strokeWidth={1} />
                {totalItems > 0 && (
                  <span className="absolute -right-2 -top-2 flex h-4 w-4 items-center justify-center rounded-full bg-gray-900 text-[9px] font-bold text-white dark:bg-white dark:text-black">
                    {totalItems}
                  </span>
                )}
              </button>
            )}

          </div>
        </div>
      </nav>

      {/* Spacer to prevent content from jumping under fixed navbar */}
      <div className="h-[73px]" />

      <MobileMenu
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />
    </>
  );
}
